{
  "schemaVersion": 3,
  "judgeId": "judge_2",
  "batchIndex": 6,
  "comparisons": [
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "dt_01_concept_07",
      "winnerId": "c8_light_luring_squid",
      "reason": "C8 tập trung vào cải tiến kỹ thuật đèn măng xông (Petromax) rất đặc trưng cho thập niên 80, tạo ra lợi thế cạnh tranh trực tiếp và rủi ro kinh tế (tiền dầu) rõ rệt hơn so với việc phơi ruốc ở Concept 07."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "dt_01_concept_08",
      "winnerId": "c8_light_luring_squid",
      "reason": "C8 thể hiện sự chủ động trong việc chế tạo công cụ (độ đèn), trong khi Concept 08 dựa nhiều vào việc 'nhớ' vị trí bãi sò, dễ vi phạm ranh giới về việc dùng ký ức làm tọa độ chính xác."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "dt_01_concept_09",
      "winnerId": "c8_light_luring_squid",
      "reason": "C8 có nhịp độ 'khoái hoạt' mạnh hơn, thành quả mẻ mực ống tươi rói ngay chương 3 phù hợp với mong muốn của độc giả nam tần hơn là việc sàng lọc muối tỉ mỉ ở Concept 09."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "dt_01_concept_10",
      "winnerId": "c8_light_luring_squid",
      "reason": "Concept 10 về du lịch trải nghiệm quá sớm so với bối cảnh 1988 và không khớp với yêu cầu 'làm giàu bằng tay nghề' biển như C8."
    },
    {
      "leftId": "c9_oyster_spat_poles",
      "rightId": "c10_net_modifications",
      "winnerId": "c10_net_modifications",
      "reason": "C10 có cơ chế 'độ lưới' mang lại kết quả ngay lập tức (chương 3 có tiền thưởng), phù hợp với yêu cầu 'thành quả sớm' hơn là việc chờ hàu lớn mất nhiều tháng ở C9."
    },
    {
      "leftId": "c9_oyster_spat_poles",
      "rightId": "dt_01_concept_01",
      "winnerId": "dt_01_concept_01",
      "reason": "Concept 01 kết nối tốt giữa kỹ năng đầu bếp và bữa cơm gia đình (trứng cá cháy tỏi), tạo cảm giác ấm áp và thực tế hơn việc cắm cọc hàu ở C9."
    },
    {
      "leftId": "c9_oyster_spat_poles",
      "rightId": "dt_01_concept_02",
      "winnerId": "dt_01_concept_02",
      "reason": "Concept 02 khai thác sâu vào nghề mắm truyền thống - một biểu tượng của biển Việt Nam, với mâu thuẫn giữa vi sinh học và kinh nghiệm cũ rất sắc nét."
    },
    {
      "leftId": "c9_oyster_spat_poles",
      "rightId": "dt_01_concept_03",
      "winnerId": "dt_01_concept_03",
      "reason": "Concept 03 có động lực nhân vật mạnh mẽ (trả nợ cho cha) và cơ chế kỹ thuật đan lưới mắt cáo gia cố điểm yếu rất cụ thể, thuyết phục hơn C9."
    },
    {
      "leftId": "c9_oyster_spat_poles",
      "rightId": "dt_01_concept_04",
      "winnerId": "c9_oyster_spat_poles",
      "reason": "C9 tạo ra một mô hình kinh tế (nuôi hàu) có tính đột phá về sản lượng hơn là việc khai thác rong biển ở Concept 04, vốn khó tạo ra sự 'giàu có' nhanh chóng."
    },
    {
      "leftId": "c9_oyster_spat_poles",
      "rightId": "dt_01_concept_05",
      "winnerId": "dt_01_concept_05",
      "reason": "Concept 05 giải quyết đúng 'điểm nghẽn' của ngành biển thập niên 80 là bảo quản lạnh, tạo ra một causal world rất logic về việc giữ giá hải sản."
    },
    {
      "leftId": "c9_oyster_spat_poles",
      "rightId": "dt_01_concept_06",
      "winnerId": "dt_01_concept_06",
      "reason": "Concept 06 về cải tạo mũi thuyền để tiết kiệm dầu là một agency cực mạnh của nhân vật chính, khớp hoàn hảo với yêu cầu 'biến hiểu biết thành mẻ hàng'."
    },
    {
      "leftId": "c9_oyster_spat_poles",
      "rightId": "dt_01_concept_07",
      "winnerId": "c9_oyster_spat_poles",
      "reason": "C9 có sự đối đầu với thiên nhiên (lũ quét, cua đá) và xung đột không gian bãi lầy kịch tính hơn quy trình phơi ruốc ở Concept 07."
    },
    {
      "leftId": "c9_oyster_spat_poles",
      "rightId": "dt_01_concept_08",
      "winnerId": "c9_oyster_spat_poles",
      "reason": "C9 xây dựng cơ sở hạ tầng (rừng cọc) thay vì chỉ đi tìm bãi có sẵn như Concept 08, thể hiện tính 'làm giàu bằng tay nghề' bền vững hơn."
    },
    {
      "leftId": "c9_oyster_spat_poles",
      "rightId": "dt_01_concept_09",
      "winnerId": "c9_oyster_spat_poles",
      "reason": "C9 mang lại cảm giác 'mỏ vàng' mới lạ ở cửa sông, trong khi Concept 09 về muối có biên lợi nhuận thấp và nhịp truyện chậm."
    },
    {
      "leftId": "c9_oyster_spat_poles",
      "rightId": "dt_01_concept_10",
      "winnerId": "c9_oyster_spat_poles",
      "reason": "C9 bám sát domain đánh bắt/nuôi trồng hải sản, trong khi Concept 10 đi quá xa vào mảng dịch vụ văn hóa không phù hợp thị hiếu nam tần niên đại."
    },
    {
      "leftId": "c10_net_modifications",
      "rightId": "dt_01_concept_01",
      "winnerId": "dt_01_concept_01",
      "reason": "Concept 01 có sự ấm áp của bữa cơm gia đình và việc tận dụng phụ phẩm (trứng cá) tạo ra sự khoái hoạt tức thì, gần gũi với đời sống hơn kỹ thuật lưới của C10."
    },
    {
      "leftId": "c10_net_modifications",
      "rightId": "dt_01_concept_02",
      "winnerId": "dt_01_concept_02",
      "reason": "Concept 02 có lộ trình phát triển từ chum mắm hỏng đến thương hiệu rõ ràng, seriality 30 chương biến hóa tốt hơn việc chỉ vá lưới ở C10."
    },
    {
      "leftId": "c10_net_modifications",
      "rightId": "dt_01_concept_03",
      "winnerId": "dt_01_concept_03",
      "reason": "Concept 03 có causal cost rõ ràng (bỏ học, thức khuya) và mâu thuẫn gia đình (cha mắc nợ) tạo động lực đọc mạnh hơn C10."
    },
    {
      "leftId": "c10_net_modifications",
      "rightId": "dt_01_concept_04",
      "winnerId": "c10_net_modifications",
      "reason": "C10 tập trung vào công cụ đánh bắt trực tiếp (lưới), tạo ra sự thay đổi trạng thái kinh tế nhanh hơn việc đi vớt rong biển ở Concept 04."
    },
    {
      "leftId": "c10_net_modifications",
      "rightId": "dt_01_concept_05",
      "winnerId": "dt_01_concept_05",
      "reason": "Concept 05 giải quyết vấn đề đá lạnh - một yếu tố then chốt của thị trường hóa ban đầu, có tầm ảnh hưởng rộng đến cả bến cá hơn là kỹ thuật lưới cá nhân của C10."
    }
  ]
}
